mapper.select:
SELECT un.id, un.notification_id, un.is_read, n.title, n.content, n.notice_type, n.send_time, n.sender_name, n.router_path FROM sys_user_notification un LEFT JOIN sys_notification n ON un.notification_id = n.id WHERE un.user_id = #{userId} AND un.is_deleted = 0 AND n.withdraw_status = 0 AND n.is_deleted = 0
AND un.is_read = #{isRead}
ORDER BY n.send_time DESC
